#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int *measurements = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &measurements[i]);
        }
        qsort(measurements, N, sizeof(int), compare);
        double sum = 0;
        for (int i = K; i < N - K; i++) {
            sum += measurements[i];
        }
        double average = sum / (N - 2 * K);
        printf("%.6f\n", average);
        free(measurements);
    }
    return 0;
}

