function readline() {
    return lines[idx++];
}

let T = parseInt(readline());
while (T--) {
    let [N, K] = readline().split(' ').map(Number);
    let measurements = readline().split(' ').map(Number);
    measurements.sort((a, b) => a - b);
    let sum = 0;
    for (let i = K; i < N - K; i++) {
        sum += measurements[i];
    }
    let average = sum / (N - 2 * K);
    console.log(average.toFixed(6));
}
